#!/usr/bin/env bash
# The COMPLETE aeon-shell foothold, end to end, inside a swerve sliver on the R1:
#   FOIL entropy collector + fat-station inference server up;
#   monster-guard admits the model ONLY by passing the PARIS quality probe
#   (which also posts its residue to the collector); then the admitted model
#   generates " Paris" as text via moonshine -> fat-station.
export PATH=/usr/local/bin:/usr/bin:/bin HOME=/root MONSTER_GUARD_HOME=/root/.mg
export GNOSIS_FOIL_CACHE_URL="http://127.0.0.1:8886/.aeon/model-forward-cache"
export FAT_STATION_PORT=8080
echo "=== aeon-shell foothold inside a swerve sliver: $(uname -m) / $(grep -m1 PRETTY_NAME /etc/os-release | cut -d= -f2) ==="
gnosis-foil-control --host 127.0.0.1 --port 8886 --flow-port 9086 >/tmp/fc.log 2>&1 &
FC=$!
TOKENIZER_GGUF_PATH=/root/qwen05.gguf fat-station --knot /root/qwen05-dense.knot --port 8080 --role both --layers 0..24 >/tmp/fs.log 2>&1 &
FS=$!
i=0; while [ $i -lt 30 ]; do { curl -s -o /dev/null http://127.0.0.1:8886/.aeon/health && grep -qi ":1F90 " /proc/net/tcp; } 2>/dev/null && break; sleep 1; i=$((i+1)); done
echo "--- 1) admission GATED on the PARIS quality probe (probe also posts FOIL entropy) ---"
monster-guard delegate qwen-0.5b-agent net,fs --ttl 3600 --qspec /root/paris.json 2>&1 | grep -iE "quality|delegated|denied"
echo "--- 2) admitted model under lease -> generate the answer as text ---"
monster-guard run --name qwen-0.5b-agent --caps net,fs --lease 60 --max 120 -- \
  /usr/local/bin/moonshine --oneoff --oneoff-tokens 1 -c "The capital of France is" 2>&1 \
  | grep -iE "^The capital| Paris$|-> " | head -3
echo "--- 3) FOIL collector holds the residue (query by key) ---"
curl -s "http://127.0.0.1:8886/.aeon/model-forward-cache?key=qwen05-dense:dense:785,6722,315,9625,374&admit=false" 2>/dev/null | tr ',' '\n' | grep -iE "cache_hit|argmax|logit|source" | head -4
kill -9 $FC $FS 2>/dev/null
echo "=== foothold complete ==="
